    __uint(type, BPF_MAP_TYPE_ARRAY);
    __uint(max_entries, 1);
    __type(key, __u32);
    __type(value, __u32); /* target tgid */
} cfg SEC(".maps");

static __always_inline int global_add_stress(__u64 *val, __u64 x)
{
    if (!val)
        return 0;

    /*
     * Multiple independent branches on unknown scalar 'x' to blow up states.
     * Each bit check introduces a verifier split.
     */
    if (x & (1ull << 0))
        (*val) += 1;
    else
        (*val) += 2;

    if (x & (1ull << 1))
        (*val) += 4;
    else
        (*val) += 8;

    if (x & (1ull << 2))
        (*val) += 16;
    else
        (*val) += 32;

    if (x & (1ull << 3))
        (*val) += 64;
    else
        (*val) += 128;

    if (x & (1ull << 4))
        (*val) += 256;
    else
        (*val) += 512;

    if (x & (1ull << 5))
        (*val) += 1024;
    else
        (*val) += 2048;

    if (x & (1ull << 6))
        (*val) += 4096;
    else
        (*val) += 8192;

    if (x & (1ull << 7))
        (*val) += 16384;
    else
        (*val) += 32768;

    if (x & (1ull << 8))
        (*val) += 65536;
    else
        (*val) += 131072;

    if (x & (1ull << 9))
        (*val) += 262144;
    else
        (*val) += 524288;

    return 1;
}

